@startuml
skinparam shadowing false
skinparam classAttributeIconSize 0
skinparam packageStyle rectangle

package "javafx" {
  class App {
    --
    start()
    main()
  }
}

class InventoryController {
  ObservableList inventoryList
}

class Item {
  String name
  String serialNumber
  BigDecimal price
  --
  get()
  set()
  toString()
}

class FileUtil {
  File file
  ObservableList list
  --
  readFromTXT()
  readFromHTML()
  readFromJSON()
  readToTxt()
  readToHTML()
  readToJSON()
}

class FileLoader {
  --
  readFromTXT()
  readFromHTML()
  readFromJSON()
}

class FileSaver {
  --
  readToTxt()
  readToHTML()
  readToJSON()
}

App *-- InventoryController
InventoryController -- Item
InventoryController -- FileUtil

FileLoader -|> FileUtil
FileSaver -|> FileUtil
@enduml
